// Get trigger data and transcript
const triggerData = $('Google Drive Trigger').first().json;
const fileName = triggerData.name || '';
const transcriptText = $input.first().json.data || '';

// 1. Extract company/business name from filename
let company = '';
if (fileName.includes(' x ')) {
  company = fileName.split(' x ')[0]
    .replace(/^(Project Scope|Meeting Notes|Discovery Call|Transcript|Proposal|Call Notes|Brief|Scope)\s+/i, '')
    .trim();
} else if (fileName.includes(' - ')) {
  company = (fileName.split(' - ')[1] || '').trim();
}

// 2. Extract speaker names from transcript (format: "Name  0:00")
const speakers = [];
const lines = transcriptText.split('\n');
for (const line of lines) {
  const match = line.match(/^([A-Za-z]+(?:\s+[A-Za-z]+)+)\s+\d+:\d+/);
  if (match) {
    const speaker = match[1].trim();
    if (!/jack\s+ramsey/i.test(speaker) &&
        !/unknown\s+speaker/i.test(speaker) &&
        !/^speaker\s*\d*$/i.test(speaker)) {
      if (!speakers.includes(speaker)) {
        speakers.push(speaker);
      }
    }
  }
}

// 3. Build CRM filter: search Business Name (title) for company, Contact Person (rich_text) for ALL speakers
const filterConditions = [];
if (company) {
  filterConditions.push({property: 'Business Name', title: {contains: company}});
}
for (const speaker of speakers) {
  filterConditions.push({property: 'Contact Person', rich_text: {contains: speaker}});
}
if (filterConditions.length === 0) {
  filterConditions.push({property: 'Business Name', title: {contains: fileName}});
}
const crmFilter = JSON.stringify({or: filterConditions});

// 4. clientName = first speaker found (for display/proposal), company for business
const clientName = speakers[0] || company || fileName;

return [{
  json: {
    clientName: clientName,
    company: company,
    speakers: speakers,
    crmFilter: crmFilter,
    meetingDate: new Date().toISOString().split('T')[0],
    transcriptText: transcriptText,
    fileId: triggerData.id,
    fileName: fileName
  }
}];

